function ExpandableText({ text, limit = 150 }) {
  const [expanded, setExpanded] = useState(false);
  if (!text) return null;
  const isLong = text.length > limit;
  const shown = expanded || !isLong ? text : text.slice(0, limit).trimEnd() + "…";
  return (
    <p style={{ fontFamily: "'EB Garamond', Georgia, serif", fontSize: "0.95rem", color: palette.bark, lineHeight: 1.7, margin: 0 }}>
      {shown}
      {isLong && (
        <span
          onClick={() => setExpanded(!expanded)}
          style={{ color: palette.moss, cursor: "pointer", marginLeft: "0.4em", fontStyle: "italic", whiteSpace: "nowrap" }}
        >
          {expanded ? " vis mindre" : " mer …"}
        </span>
      )}
    </p>
  );
}

function AnimalVideoGrid() {
  const [openVideoId, setOpenVideoId] = useState(null);
  return (
    <div id="dyrevideoer" style={{ borderTop: `1px solid ${palette.fog}`, padding: "2rem 0 3rem 0" }}>
      <h2 style={{ fontFamily: "'EB Garamond', Georgia, serif", fontSize: "1.4rem", fontWeight: 400, color: palette.moss, margin: "0 0 1.2rem 0" }}>
        Dyr jeg har møtt underveis
      </h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "1.5rem" }}>
        {animalVideos.map((v) => (
          <div key={v.id}>
            {openVideoId === v.id ? (
              <div style={{ position: "relative", width: "100%", aspectRatio: "16/9", borderRadius: "2px", overflow: "hidden" }}>
                <iframe
                  src={`https://www.youtube.com/embed/${v.id}?autoplay=1${v.startTime ? `&start=${v.startTime}` : ""}`}
                  title={v.title}
                  frameBorder="0"
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                  allowFullScreen
                  style={{ width: "100%", height: "100%", display: "block" }}
                />
              </div>
            ) : (
              <div
                onClick={() => setOpenVideoId(v.id)}
                style={{ position: "relative", width: "100%", aspectRatio: "16/9", borderRadius: "2px", overflow: "hidden", cursor: "pointer" }}
              >
                <img
                  src={v.thumbnail || `https://img.youtube.com/vi/${v.id}/hqdefault.jpg`}
                  alt={v.title}
                  style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
                />
                <div style={{
                  position: "absolute", top: 0, left: 0, right: 0, bottom: 0,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  background: "rgba(0,0,0,0.15)",
                }}>
                  <div style={{
                    width: "60px", height: "60px", borderRadius: "50%",
                    background: "rgba(0,0,0,0.6)", display: "flex", alignItems: "center", justifyContent: "center",
                  }}>
                    <div style={{
                      width: 0, height: 0,
                      borderTop: "12px solid transparent", borderBottom: "12px solid transparent",
                      borderLeft: "20px solid white", marginLeft: "4px",
                    }} />
                  </div>
                </div>
              </div>
            )}
            <h3 style={{ fontFamily: "'EB Garamond', Georgia, serif", fontSize: "1.05rem", fontWeight: 400, color: palette.ink, margin: "0.8rem 0 0.4rem 0" }}>
              {v.title}
            </h3>
            <ExpandableText text={v.text} />
          </div>
        ))}
      </div>
    </div>
  );
}

